#!/usr/bin/env bun
/**
 * stage-content-advanced.ts — Content Advanced Scenario Stager
 *
 * Covers zero-coverage content shapes from FAILURE-TAXONOMY.md:
 *   N-10: Very large files (performance)
 *   N-11: Pattern in generated scaffold
 *   N-12: Concatenated/bundled content
 *   N-13: JSON structure assertion (key path)
 *   N-14: YAML/TOML config value assertion
 *   N-15: Environment variable reference in file
 *   N-16: Import/require graph assertion
 *   N-17: BOM (Byte Order Mark) offset
 *
 * Pure tier — tests grounding gate content predicate handling.
 */

import { writeFileSync } from 'fs';
import { resolve } from 'path';

const outPath = resolve(__dirname, '../../fixtures/scenarios/content-advanced-staged.json');
const scenarios: any[] = [];
let id = 1;

function push(s: any) {
  scenarios.push({ id: `cnt-adv-${String(id++).padStart(3, '0')}`, ...s });
}

// =============================================================================
// N-10: Very large files (performance)
// =============================================================================

push({
  description: 'N-10: Pattern exists in normal-sized source — passes',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'server.js',
    pattern: 'createServer',
  }],
  expectedSuccess: true,
  tags: ['content', 'large_file_performance', 'N-10'],
});

push({
  description: 'N-10: Pattern from hypothetical 10MB file — fabricated',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'server.js',
    pattern: 'LINE_99999_OF_GENERATED_OUTPUT',
  }],
  expectedSuccess: false,
  expectedFailedGate: 'grounding',
  tags: ['content', 'large_file_performance', 'N-10'],
});

push({
  description: 'N-10: Large file reference — file does not exist',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'generated-10mb-output.log',
    pattern: 'anything',
  }],
  expectedSuccess: false,
  expectedFailedGate: 'grounding',
  tags: ['content', 'large_file_performance', 'N-10'],
});

// =============================================================================
// N-11: Pattern in generated scaffold
// =============================================================================

