// =============================================================================
// N-17: BOM (Byte Order Mark) offset
// =============================================================================

push({
  description: 'N-17: Normal content without BOM — passes',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'server.js',
    pattern: 'http',
  }],
  expectedSuccess: true,
  tags: ['content', 'bom_offset', 'N-17'],
});

push({
  description: 'N-17: BOM character in content claim — not in source',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'server.js',
    pattern: '\uFEFF// BOM-prefixed file',
  }],
  expectedSuccess: false,
  expectedFailedGate: 'grounding',
  tags: ['content', 'bom_offset', 'N-17'],
});

push({
  description: 'N-17: UTF-8 BOM at file start claim — fabricated',
  edits: [],
  predicates: [{
    type: 'content',
    file: 'server.js',
    pattern: 'EF BB BF const',
  }],
  expectedSuccess: false,
  expectedFailedGate: 'grounding',
  tags: ['content', 'bom_offset', 'N-17'],
});

// =============================================================================
// Summary
// =============================================================================

writeFileSync(outPath, JSON.stringify(scenarios, null, 2));

const tagCounts: Record<string, number> = {};
for (const s of scenarios) {
  const tag = s.tags[2] || s.tags[1] || 'unknown';
  tagCounts[tag] = (tagCounts[tag] || 0) + 1;
}

console.log(`Generated ${scenarios.length} content advanced scenarios → ${outPath}\n`);
console.log('By taxonomy shape:');
for (const [tag, count] of Object.entries(tagCounts).sort((a, b) => b[1] - a[1])) {
  console.log(`  ${tag.padEnd(35)} ${count}`);
}
